INSERT INTO quotes (id, text, author, category, lang, swipe_dir, pack_name, is_premium, content_type, sub_category, tags, is_hidden_mode, locked_by) VALUES
(gen_random_uuid(), 'The cosmos is within us. We are made of star-stuff. We are a way for the universe to know itself.', 'Carl Sagan', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Science is a way of thinking much more than it is a body of knowledge.', 'Carl Sagan', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Somewhere, something incredible is waiting to be known.', 'Carl Sagan', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'creativity'], true, 'science'),
(gen_random_uuid(), 'We are star dust, we are golden, and we''ve got to get ourselves back to the garden.', 'Carl Sagan', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The universe is under no obligation to make sense to you.', 'Neil deGrasse Tyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'For me, I am driven by two main philosophies: know more today about the world than I knew yesterday, and lessen the suffering of others.', 'Neil deGrasse Tyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'self_improvement', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'We are all connected; to each other, biologically; to the earth, chemically; to the rest of the universe atomically.', 'Neil deGrasse Tyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The good thing about science is that it''s true whether or not you believe in it.', 'Neil deGrasse Tyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Science literacy is a vaccine against the charlatans of the world that would exploit your ignorance.', 'Neil deGrasse Tyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'wisdom', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'The measure of intelligence is the ability to change.', 'Charles Darwin', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['self_improvement', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'It is not the strongest of the species that survives, nor the most intelligent, but the one most responsive to change.', 'Charles Darwin', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['self_improvement', 'wisdom', 'discipline'], true, 'science'),
(gen_random_uuid(), 'A man who dares to waste one hour of time has not discovered the value of life.', 'Charles Darwin', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['discipline', 'focus', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'Ignorance more frequently begets confidence than does knowledge.', 'Charles Darwin', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'In the long history of humankind those who learned to collaborate and improvise most effectively have prevailed.', 'Charles Darwin', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'discipline'], true, 'science'),
(gen_random_uuid(), 'Nothing in life is to be feared; it is only to be understood.', 'Marie Curie', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Be less curious about people and more curious about ideas.', 'Marie Curie', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'focus'], true, 'science'),
(gen_random_uuid(), 'I was taught that the way of progress was neither swift nor easy.', 'Marie Curie', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['discipline', 'self_improvement', 'learning'], true, 'science'),
(gen_random_uuid(), 'One never notices what has been done; one can only see what remains to be done.', 'Marie Curie', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['discipline', 'focus', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'I have no dress except the one I wear every day. If you are going to be kind enough to give me one, please let it be practical and dark so that I can put it on afterwards to go to the laboratory.', 'Marie Curie', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['discipline', 'focus', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'The love for all living creatures is the most noble attribute of man.', 'Charles Darwin', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Animals, whom we have made our slaves, we do not like to consider our equals.', 'Charles Darwin', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'What science cannot tell us, mankind cannot know.', 'Bertrand Russell', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The good life is one inspired by love and guided by knowledge.', 'Bertrand Russell', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'Science may set limits to knowledge, but should not set limits to imagination.', 'Bertrand Russell', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'creativity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The whole problem with the world is that fools and fanatics are always so certain of themselves, and wise people so full of doubts.', 'Bertrand Russell', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'To conquer fear is the beginning of wisdom.', 'Bertrand Russell', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'self_improvement', 'learning'], true, 'science'),
(gen_random_uuid(), 'In science it often happens that scientists say, you know that''s a really good argument; my position is mistaken.', 'Carl Sagan', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'The brain is like a muscle. When it is in use we feel very good. Understanding is joyous.', 'Carl Sagan', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'curiosity', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'Extinction is the rule. Survival is the exception.', 'Carl Sagan', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Every kid starts out as a natural-born scientist, and then we beat it out of them.', 'Carl Sagan', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'The universe is a pretty big place. If it''s just us, seems like an awful waste of space.', 'Carl Sagan', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Science is the great antidote to the poison of enthusiasm and superstition.', 'Adam Smith', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'The fact that we live at the bottom of a deep gravity well, on the surface of a gas-covered planet going around a nuclear fireball, is one of my favorite science facts.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Study hard what interests you the most in the most undisciplined, irreverent and original manner possible.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'creativity'], true, 'science'),
(gen_random_uuid(), 'The first principle is that you must not fool yourself — and you are the easiest person to fool.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'self_improvement', 'learning'], true, 'science'),
(gen_random_uuid(), 'I would rather have questions that can''t be answered than answers that can''t be questioned.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'If you thought that science was certain — well, that is just an error on your part.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Nature uses only the longest threads to weave her patterns, so each small piece of her fabric reveals the organization of the entire tapestry.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Science is the belief in the ignorance of experts.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The beauty of a living thing is not the atoms that go into it, but the way those atoms are put together.', 'Carl Sagan', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Only by understanding the natural world can we hope to preserve it.', 'David Attenborough', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'No one will protect what they don''t care about; and no one will care about what they have never experienced.', 'David Attenborough', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'It''s surely our responsibility to do everything within our power to create a planet that provides a home not just for us, but for all life on earth.', 'David Attenborough', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'discipline'], true, 'science'),
(gen_random_uuid(), 'I just wish the world was twice as big and half of it was still unexplored.', 'David Attenborough', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'creativity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The question is, are we happy to suppose that our grandchildren may never be able to see an elephant except in a picture book?', 'David Attenborough', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'If we don''t take action, the collapse of our civilisations and the extinction of much of the natural world is on the horizon.', 'David Attenborough', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'discipline', 'learning'], true, 'science'),
(gen_random_uuid(), 'The least I can do is speak out for those who cannot speak for themselves.', 'Jane Goodall', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'discipline', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'You cannot get through a single day without having an impact on the world around you. What you do makes a difference.', 'Jane Goodall', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'discipline', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'What you do makes a difference, and you have to decide what kind of difference you want to make.', 'Jane Goodall', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'self_improvement', 'discipline'], true, 'science'),
(gen_random_uuid(), 'Every individual matters. Every individual has a role to play. Every individual makes a difference.', 'Jane Goodall', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'self_improvement', 'discipline'], true, 'science'),
(gen_random_uuid(), 'Change happens by listening and then starting a dialogue with the people who are doing something you don''t believe is right.', 'Jane Goodall', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'The more clearly we can focus our attention on the wonders and realities of the universe about us, the less taste we shall have for destruction.', 'Rachel Carson', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The human race is challenged more than ever before to demonstrate our mastery — not over nature but of ourselves.', 'Rachel Carson', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'self_improvement', 'discipline'], true, 'science'),
(gen_random_uuid(), 'Those who contemplate the beauty of the earth find reserves of strength that will endure as long as life lasts.', 'Rachel Carson', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'In every walk with nature, one receives far more than he seeks.', 'John Muir', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The clearest way into the universe is through a forest wilderness.', 'John Muir', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The power of imagination makes us infinite.', 'John Muir', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['creativity', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Biodiversity is the totality of all inherited variation in the life forms of Earth.', 'E.O. Wilson', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'curiosity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Destroying a tropical rainforest for profit is like burning all the paintings of the Louvre to cook dinner.', 'E.O. Wilson', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'You are capable of more than you know. Choose a goal that seems right for you and strive to be the best in your field.', 'E.O. Wilson', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['self_improvement', 'discipline', 'focus'], true, 'science'),
(gen_random_uuid(), 'The brain and its satellite glands have now been probed to the point where no particular site remains that can reasonably be supposed to harbor a nonphysical mind.', 'E.O. Wilson', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The human mind evolved to believe in the gods. It did not evolve to believe in biology.', 'E.O. Wilson', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'We are drowning in information, while starving for wisdom.', 'E.O. Wilson', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'Evolution is not a theory in crisis. It is not teetering on the verge of collapse.', 'Stephen Jay Gould', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'I am, somehow, less interested in the weight and convolutions of Einstein''s brain than in the near-certainty that people of equal talent have lived and died in cotton fields and sweatshops.', 'Stephen Jay Gould', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Science is not a heartless pursuit of objective information. It is a creative human activity.', 'Stephen Jay Gould', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['creativity', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The most important scientific revolutions all include, as their only common feature, the dethronement of human arrogance from one pedestal after another.', 'Stephen Jay Gould', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'In science, ''fact'' can only mean ''confirmed to such a degree that it would be perverse to withhold provisional assent.''', 'Stephen Jay Gould', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Each species is a masterpiece, a creation assembled with extreme care and genius.', 'E.O. Wilson', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The more you know, the more you realize how much you don''t know.', 'Aristotle', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'It is the mark of an educated mind to be able to entertain a thought without accepting it.', 'Aristotle', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'All men by nature desire knowledge.', 'Aristotle', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The whole is more than the sum of its parts.', 'Aristotle', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'In science and in medicine, the greatest discoveries often come from those who refuse to take ''no'' for an answer.', 'Jonas Salk', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['discipline', 'focus', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'The reward for work well done is the opportunity to do more.', 'Jonas Salk', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['discipline', 'self_improvement', 'focus'], true, 'science'),
(gen_random_uuid(), 'Hope lies in dreams, in imagination, and in the courage of those who dare to make dreams into reality.', 'Jonas Salk', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['creativity', 'self_improvement', 'discipline'], true, 'science'),
(gen_random_uuid(), 'I have had dreams and I have had nightmares. I overcame the nightmares because of my dreams.', 'Jonas Salk', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['self_improvement', 'discipline', 'focus'], true, 'science'),
(gen_random_uuid(), 'When you inoculate children with a polio vaccine, you don''t sleep well for a few nights.', 'Jonas Salk', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['discipline', 'focus', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'Fleming did not discover penicillin by accident. He noticed something that others had ignored.', 'Alexander Fleming', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'focus', 'learning'], true, 'science'),
(gen_random_uuid(), 'One sometimes finds what one is not looking for.', 'Alexander Fleming', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'A good scientist is a person with original ideas. A good engineer is a person who makes a design that works with as few original ideas as possible.', 'Freeman Dyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['creativity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Science and technology are the engines of prosperity.', 'Linus Pauling', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'creativity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The best way to have a good idea is to have lots of ideas.', 'Linus Pauling', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['creativity', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Satisfaction of one''s curiosity is one of the greatest sources of happiness in life.', 'Linus Pauling', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'I am a scientist. I believe in facts over values, evidence over ideology.', 'Linus Pauling', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Science never solves a problem without creating ten more.', 'George Bernard Shaw', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Science is organized knowledge. Wisdom is organized life.', 'Immanuel Kant', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'In science, one tries to tell people something that no one knew before. In poetry, one tries to say something that everyone knows already.', 'Paul Dirac', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['creativity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Louis Pasteur''s theory of germs is ridiculous fiction.', 'Pierre Pachet', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Chance favors the prepared mind.', 'Louis Pasteur', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['discipline', 'focus', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'Let me tell you the secret that has led me to my goal. My only strength lies in my tenacity.', 'Louis Pasteur', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['discipline', 'focus', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'Science knows no country, because knowledge belongs to humanity, and is the torch which illuminates the world.', 'Louis Pasteur', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Do not let what you cannot do interfere with what you can do.', 'John Wooden', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['discipline', 'focus', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'In science, there are no shortcuts to truth.', 'Karl Popper', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'discipline'], true, 'science'),
(gen_random_uuid(), 'Our knowledge can only be finite, while our ignorance must necessarily be infinite.', 'Karl Popper', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Science must begin with myths, and with the criticism of myths.', 'Karl Popper', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Whenever a theory appears to you as the only possible one, take this as a sign that you have neither understood the theory nor the problem it was intended to solve.', 'Karl Popper', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'True ignorance is not the absence of knowledge, but the refusal to acquire it.', 'Karl Popper', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'All science is either physics or stamp collecting.', 'Ernest Rutherford', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'We haven''t got the money, so we''ve got to think.', 'Ernest Rutherford', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['creativity', 'wisdom', 'focus'], true, 'science'),
(gen_random_uuid(), 'If your experiment needs statistics, you ought to have done a better experiment.', 'Ernest Rutherford', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'focus', 'learning'], true, 'science'),
(gen_random_uuid(), 'An experiment is a question which science poses to Nature, and a measurement is the recording of Nature''s answer.', 'Max Planck', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'curiosity', 'focus'], true, 'science'),
(gen_random_uuid(), 'Scientific discovery and scientific knowledge have been achieved only by those who have gone in pursuit of it without any practical purpose whatsoever in view.', 'Max Planck', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'focus', 'learning'], true, 'science'),
