(gen_random_uuid(), 'Science feeds on mystery. As a scientist, I don''t know what I''ll find out next.', 'Richard Dawkins', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
