(gen_random_uuid(), 'All knowledge is connected to all other knowledge. The fun is in making the connections.', 'Arthur Aufderheide', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The whole of science is nothing more than a refinement of everyday thinking.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Reality is merely an illusion, albeit a very persistent one.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'If you can''t explain it simply, you don''t understand it well enough.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'focus'], true, 'science'),
(gen_random_uuid(), 'Try not to become a man of success. Rather become a man of value.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'self_improvement', 'discipline'], true, 'science'),
(gen_random_uuid(), 'Logic will get you from A to B. Imagination will take you everywhere.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Not everything that can be counted counts, and not everything that counts can be counted.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Science is the process that takes us from confusion to understanding.', 'Brian Greene', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The universe is not only stranger than we imagine, it is stranger than we can imagine.', 'J.B.S. Haldane', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The history of life on Earth is a history of interaction between living things and their surroundings.', 'Rachel Carson', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Nature does not hurry, yet everything is accomplished.', 'Lao Tzu', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'discipline', 'learning'], true, 'science'),
(gen_random_uuid(), 'The earth does not belong to us; we belong to the earth.', 'Chief Seattle', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Nature is the source of all true knowledge.', 'Leonardo da Vinci', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Science is the great antidote to the poison of enthusiasm and superstition.', 'Adam Smith', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'From tiny acorns grow mighty oaks — and from the simplest of cells, the most complex of beings.', 'Ernst Haeckel', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The tree of life is a tree of knowledge.', 'Ernst Haeckel', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The secret of getting ahead is getting started.', 'Louis Pasteur', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['discipline', 'focus', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'Science grows and beauty dwindles.', 'Alfred Lord Tennyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'There is something fascinating about science. One gets such wholesale returns of conjecture out of such a trifling investment of fact.', 'Mark Twain', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Science is always wrong. It never solves a problem without creating ten more.', 'George Bernard Shaw', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'To be a scientist is to be naive. We are so focused on understanding the world that we fail to consider that the world may not want to be understood.', 'Niels Bohr', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The large-scale structure of the universe is the story of gravity''s struggle against the initial bang.', 'Sean Carroll', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The real voyage of discovery consists not in seeking new landscapes, but in having new eyes.', 'Marcel Proust', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Every discovery I ever made, I gambled that the truth was there, and then I acted on it in faith until I could prove its existence.', 'Arthur Compton', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['discipline', 'focus', 'learning'], true, 'science'),
(gen_random_uuid(), 'The most beautiful thing we can experience is the mysterious. It is the source of all true art and science.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'creativity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The important thing is not to stop questioning; curiosity has its own reason for existing.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Our oceans are dying, and with them, us.', 'Sylvia Earle', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The sea is as near as we come to another world.', 'Anne Stevenson', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The way to find out if something is alive is to watch it change.', 'Karl Knausgård', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'If the brain were so simple we could understand it, we would be so simple we couldn''t.', 'Lyall Watson', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Neuroscience is not just about understanding the brain; it is about understanding what it means to be human.', 'António Damásio', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Consciousness is the greatest mystery in all of science.', 'David Chalmers', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The mind is what the brain does.', 'Steven Pinker', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Language is a window into human nature.', 'Steven Pinker', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The world is not falling apart; in many ways it is coming together.', 'Steven Pinker', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Progress is not automatic. You have to believe in data, in reason, in science.', 'Steven Pinker', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'discipline'], true, 'science'),
(gen_random_uuid(), 'The brain is the most complex object in the known universe.', 'Michio Kaku', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Science is the engine of prosperity.', 'Michio Kaku', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'wisdom', 'creativity'], true, 'science'),
(gen_random_uuid(), 'The purpose of science is not to know, but to understand.', 'Freeman Dyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'New science has always come from young people who are willing to ask questions that older scientists consider too risky.', 'Freeman Dyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'The best scientist is open to experience and begins with romance — the idea that anything is possible.', 'Ray Bradbury', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'creativity', 'learning'], true, 'science'),
(gen_random_uuid(), 'To know one''s ignorance is the beginning of wisdom.', 'Confucius', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'Real knowledge is to know the extent of one''s ignorance.', 'Confucius', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'The function of science is to reassure; the purpose of art is to upset.', 'Georges Braque', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'creativity'], true, 'science'),
(gen_random_uuid(), 'We shall not cease from exploration, and the end of all our exploring will be to arrive where we started and know the place for the first time.', 'T.S. Eliot', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The greatest obstacle to discovery is not ignorance — it is the illusion of knowledge.', 'Daniel Boorstin', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'Discovery is seeing what everybody else has seen, and thinking what nobody else has thought.', 'Albert von Szent-Györgyi', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['creativity', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The capacity to be puzzled is the premise of all creation, be it in art or in science.', 'Erich Fromm', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'creativity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Science is the poetry of reality.', 'Richard Dawkins', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'creativity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The universe is under no obligation to make sense to you.', 'Neil deGrasse Tyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'In science, self-satisfaction is death. Personal self-satisfaction is the death of the scientist.', 'Jacques-Yves Cousteau', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['discipline', 'self_improvement', 'focus'], true, 'science'),
(gen_random_uuid(), 'The sea, once it casts its spell, holds one in its net of wonder forever.', 'Jacques-Yves Cousteau', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'We protect what we love.', 'Jacques-Yves Cousteau', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'discipline', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'Man has only one genuine vocation — to find his way to himself.', 'Herman Hesse', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'self_improvement', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'The world is full of obvious things which nobody by any chance ever observes.', 'Arthur Conan Doyle', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'focus'], true, 'science'),
(gen_random_uuid(), 'When you have eliminated the impossible, whatever remains, however improbable, must be the truth.', 'Arthur Conan Doyle', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The best way to predict the future is to invent it.', 'Alan Kay', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['creativity', 'discipline', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'The only source of knowledge is experience.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'wisdom', 'discipline'], true, 'science'),
(gen_random_uuid(), 'All truths are easy to understand once they are discovered; the point is to discover them.', 'Galileo Galilei', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Mathematics is the language in which God has written the universe.', 'Galileo Galilei', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'I could have gone on flying through space forever.', 'Yuri Gagarin', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'To boldly go where no man has gone before.', 'Gene Roddenberry', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'discipline', 'creativity'], true, 'science'),
(gen_random_uuid(), 'From the moment I fell down that rabbit hole I''ve been told what I must do and who I must be. I''ve been shrunk, stretched, scratched, and stuffed into a tea pot. I believe it''s time to have a say.', 'Lewis Carroll', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['self_improvement', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'The scientific attitude of mind involves a sweeping away of all other desires in the interest of the desire to know.', 'Bertrand Russell', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'focus', 'discipline'], true, 'science'),
(gen_random_uuid(), 'What is a scientist after all? It is a curious man looking through a keyhole, the keyhole of nature, trying to know what''s going on.', 'Jacques-Yves Cousteau', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'I see a worm in the dirt and I know there''s a whole universe in that worm.', 'Jane Goodall', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The more I read, the more I acquire, the more certain I am that I know nothing.', 'Voltaire', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'The scientist is not a person who gives the right answers, he''s one who asks the right questions.', 'Claude Levi-Strauss', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'What we know is a drop, what we don''t know is an ocean.', 'Isaac Newton', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'If I have seen further, it is by standing on the shoulders of giants.', 'Isaac Newton', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'Nature is pleased with simplicity.', 'Isaac Newton', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'focus', 'learning'], true, 'science'),
(gen_random_uuid(), 'Tact is the knack of making a point without making an enemy.', 'Isaac Newton', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'self_improvement', 'learning'], true, 'science'),
(gen_random_uuid(), 'Truth is ever to be found in simplicity, and not in the multiplicity and confusion of things.', 'Isaac Newton', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'focus', 'learning'], true, 'science'),
(gen_random_uuid(), 'Genius is one percent inspiration and ninety-nine percent perspiration.', 'Thomas Edison', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['discipline', 'focus', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'I have not failed. I''ve just found 10,000 ways that won''t work.', 'Thomas Edison', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['discipline', 'self_improvement', 'focus'], true, 'science'),
(gen_random_uuid(), 'Our greatest weakness lies in giving up. The most certain way to succeed is always to try just one more time.', 'Thomas Edison', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['discipline', 'focus', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'There are no secrets to success. It is the result of preparation, hard work, and learning from failure.', 'Colin Powell', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['discipline', 'self_improvement', 'focus'], true, 'science'),
(gen_random_uuid(), 'The important thing is not to stop questioning. Curiosity has its own reason for existence.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Science is a way of life. Science is a perspective. Science is the process that takes us from confusion to understanding.', 'Brian Greene', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'The universe is big, it''s vast and complicated and ridiculous, and sometimes, very rarely, impossible things just happen and we call them miracles.', 'Neil deGrasse Tyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'We are not separate from nature; we are part of it.', 'Rachel Carson', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The sea is everything. It covers seven-tenths of the terrestrial globe.', 'Jules Verne', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'In the beginning was the gene.', 'Richard Dawkins', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Science enriches all of human life.', 'Carl Sagan', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Every generation needs a new revolution.', 'Thomas Jefferson', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'self_improvement', 'learning'], true, 'science'),
(gen_random_uuid(), 'The most dangerous experiment we can conduct is to continue doing things as we have always done.', 'Dee Hock', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'self_improvement', 'creativity'], true, 'science'),
(gen_random_uuid(), 'Science has never drummed up quite as effective a tranquilizing agent as a sunny spring day.', 'W. Earl Hall', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Facts do not cease to exist because they are ignored.', 'Aldous Huxley', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'The great end of science is to make the works of the Almighty intelligible to human understanding.', 'Robert Boyle', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Physics is becoming so weird that anything goes.', 'Michio Kaku', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'I am enough of an artist to draw freely upon my imagination.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['creativity', 'curiosity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The most important discoveries will provide answers to questions that we do not yet know how to ask.', 'John N. Bahcall', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Knowing a great deal is not the same as being smart; intelligence is not information alone but also judgment.', 'Carl Sagan', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'We were all humans until race disconnected us, religion separated us, politics divided us, and wealth classified us.', 'Pravinee Hurbungs', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Science is the one human endeavor whose laws are universal — they work the same everywhere in the universe.', 'Neil deGrasse Tyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Understanding is the road to knowledge, but knowledge is not the road to understanding.', 'Roy T. Bennett', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'Science is the record of dead religions.', 'Oscar Wilde', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Biology is the study of complicated things that give the appearance of having been designed for a purpose.', 'Richard Dawkins', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Look up at the stars and not down at your feet. Try to make sense of what you see, and wonder about what makes the universe exist.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The greatest enemy of knowledge is not ignorance, it is the illusion of knowledge.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'Intelligence is the ability to adapt to change.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'self_improvement', 'learning'], true, 'science'),
(gen_random_uuid(), 'However difficult life may seem, there is always something you can do and succeed at.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['discipline', 'self_improvement', 'focus'], true, 'science'),
(gen_random_uuid(), 'The past, like the future, is indefinite and exists only as a spectrum of possibilities.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'I believe alien life is quite common in the universe, although intelligent life is less so.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'A scientist, whether theorist or experimenter, puts forward statements, or systems of statements, and tests them step by step.', 'Karl Popper', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['discipline', 'learning', 'focus'], true, 'science'),
(gen_random_uuid(), 'What makes something ''good science'' is the possibility of being wrong.', 'Karl Popper', 'philosophy', 'en', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science')
INSERT INTO quotes (id, text, author, category, lang, swipe_dir, pack_name, is_premium, content_type, sub_category, tags, is_hidden_mode, locked_by) VALUES
(gen_random_uuid(), 'La ciencia es una forma de pensar mucho más que un cuerpo de conocimientos.', 'Carl Sagan', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Somos polvo de estrellas. Somos la manera que tiene el universo de conocerse a sí mismo.', 'Carl Sagan', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La capacidad de asombrarse es el principio de toda ciencia.', 'Carl Sagan', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'El universo no está obligado a tener sentido para ti.', 'Neil deGrasse Tyson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'La buena noticia de la ciencia es que es verdad, lo creas o no.', 'Neil deGrasse Tyson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Todos estamos conectados entre sí biológicamente, a la tierra químicamente y al resto del universo atómicamente.', 'Neil deGrasse Tyson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La medida de la inteligencia es la capacidad de cambiar.', 'Charles Darwin', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['self_improvement', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'No es el más fuerte de la especie el que sobrevive, sino el que más se adapta al cambio.', 'Charles Darwin', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['self_improvement', 'wisdom', 'discipline'], true, 'science'),
(gen_random_uuid(), 'La ignorancia con más frecuencia engendra confianza que el conocimiento.', 'Charles Darwin', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'Nada en la vida es para ser temido, solo para ser comprendido.', 'Marie Curie', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Sé menos curiosa sobre las personas y más curiosa sobre las ideas.', 'Marie Curie', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'focus'], true, 'science'),
(gen_random_uuid(), 'Nunca se da cuenta de lo que se ha hecho; solo se puede ver lo que queda por hacer.', 'Marie Curie', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['discipline', 'focus', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'Fui instruida a que el camino del progreso no era ni rápido ni fácil.', 'Marie Curie', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['discipline', 'self_improvement', 'learning'], true, 'science'),
(gen_random_uuid(), 'La ciencia puede establecer límites al conocimiento, pero no debe establecer límites a la imaginación.', 'Bertrand Russell', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'creativity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Lo que la ciencia no puede decirme, la humanidad tampoco puede saberlo.', 'Bertrand Russell', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Conquistar el miedo es el comienzo de la sabiduría.', 'Bertrand Russell', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'self_improvement', 'learning'], true, 'science'),
(gen_random_uuid(), 'El universo es un libro del que solo hemos leído la primera página.', 'Carl Sagan', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'El cerebro es como un músculo. Cuando está en uso nos sentimos muy bien.', 'Carl Sagan', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'curiosity', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'La extinción es la regla. La supervivencia es la excepción.', 'Carl Sagan', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Todo niño nace como científico nato, y luego se lo sacamos.', 'Carl Sagan', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'Solo si entendemos el mundo natural podemos esperar preservarlo.', 'David Attenborough', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Nadie protegerá lo que no le importa; y a nadie le importará lo que nunca ha experimentado.', 'David Attenborough', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Simplemente desearía que el mundo fuera el doble de grande y que la mitad aún estuviera sin explorar.', 'David Attenborough', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'creativity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Lo mínimo que puedo hacer es hablar por aquellos que no pueden hablar por sí mismos.', 'Jane Goodall', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'discipline', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'No puedes pasar un solo día sin tener un impacto en el mundo que te rodea.', 'Jane Goodall', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'discipline', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'Cada individuo importa. Cada individuo tiene un papel que desempeñar. Cada individuo marca la diferencia.', 'Jane Goodall', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'self_improvement', 'discipline'], true, 'science'),
(gen_random_uuid(), 'Cuanto más claramente podamos centrar nuestra atención en las maravillas del universo, menos gusto tendremos por la destrucción.', 'Rachel Carson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Quienes contemplan la belleza de la tierra encuentran reservas de fuerza que durarán mientras dure la vida.', 'Rachel Carson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'La raza humana es desafiada como nunca antes a demostrar su maestría, no sobre la naturaleza sino sobre sí misma.', 'Rachel Carson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'self_improvement', 'discipline'], true, 'science'),
(gen_random_uuid(), 'En cada paseo con la naturaleza, uno recibe mucho más de lo que busca.', 'John Muir', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'El camino más claro hacia el universo es a través de un bosque salvaje.', 'John Muir', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Estamos ahogándonos en información mientras nos morimos de hambre de sabiduría.', 'E.O. Wilson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'Destruir una selva tropical para obtener ganancias es como quemar todos los cuadros del Louvre para cocinar la cena.', 'E.O. Wilson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Eres capaz de más de lo que crees. Elige un objetivo que parezca correcto para ti y esfuérzate por ser el mejor en tu campo.', 'E.O. Wilson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['self_improvement', 'discipline', 'focus'], true, 'science'),
(gen_random_uuid(), 'Cada especie es una obra maestra, una creación ensamblada con extremo cuidado y genio.', 'E.O. Wilson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La ciencia no es un conjunto de hechos. Es un método para decidir qué elegimos creer.', 'E.O. Wilson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'La más importante de las revoluciones científicas incluye el derrocamiento de la arrogancia humana.', 'Stephen Jay Gould', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'La ciencia no es una búsqueda desalmada de información objetiva. Es una actividad humana creativa.', 'Stephen Jay Gould', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['creativity', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'En ciencia, un hecho solo puede significar algo confirmado a tal grado que sería perverso negarle asentimiento provisional.', 'Stephen Jay Gould', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Es la marca de una mente educada poder entretener un pensamiento sin aceptarlo.', 'Aristóteles', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Todos los hombres por naturaleza desean conocer.', 'Aristóteles', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'El todo es más que la suma de sus partes.', 'Aristóteles', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'La recompensa por el trabajo bien hecho es la oportunidad de hacer más.', 'Jonas Salk', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['discipline', 'self_improvement', 'focus'], true, 'science'),
(gen_random_uuid(), 'La esperanza yace en los sueños, en la imaginación y en el coraje de quienes se atreven a convertir los sueños en realidad.', 'Jonas Salk', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['creativity', 'self_improvement', 'discipline'], true, 'science'),
(gen_random_uuid(), 'He tenido sueños y he tenido pesadillas. Superé las pesadillas por mis sueños.', 'Jonas Salk', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['self_improvement', 'discipline', 'focus'], true, 'science'),
(gen_random_uuid(), 'El azar favorece la mente preparada.', 'Louis Pasteur', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['discipline', 'focus', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'El secreto que me llevó a mi objetivo es que toda mi fuerza reside en mi tenacidad.', 'Louis Pasteur', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['discipline', 'focus', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'La ciencia no conoce patria porque el conocimiento pertenece a la humanidad.', 'Louis Pasteur', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'A veces uno encuentra lo que no está buscando.', 'Alexander Fleming', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Nuestro conocimiento solo puede ser finito, mientras que nuestra ignorancia necesariamente debe ser infinita.', 'Karl Popper', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'La ignorancia verdadera no es la ausencia de conocimiento, sino la negativa a adquirirlo.', 'Karl Popper', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'La ciencia debe comenzar con mitos y con la crítica de los mitos.', 'Karl Popper', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'No tenemos dinero, así que tenemos que pensar.', 'Ernest Rutherford', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['creativity', 'wisdom', 'focus'], true, 'science'),
(gen_random_uuid(), 'Toda la ciencia es física o coleccionismo de sellos.', 'Ernest Rutherford', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Si tu experimento necesita estadísticas, deberías haber hecho un experimento mejor.', 'Ernest Rutherford', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'focus', 'learning'], true, 'science'),
(gen_random_uuid(), 'La naturaleza es un todo vivo, no un agregado muerto.', 'Alexander von Humboldt', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La visión del mundo más peligrosa es la de quienes no han visto el mundo.', 'Alexander von Humboldt', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'La medicina es la ciencia de la incertidumbre y el arte de la probabilidad.', 'William Osler', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'El buen médico trata la enfermedad; el gran médico trata al paciente que tiene la enfermedad.', 'William Osler', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'discipline', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'Una inversión en conocimiento paga el mejor interés.', 'Benjamin Franklin', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'wisdom', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'Dímelo y lo olvido. Enséñame y lo recuerdo. Involúcrame y aprendo.', 'Benjamin Franklin', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'wisdom', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'La mente no es un recipiente para llenar, sino un fuego para encender.', 'Plutarco', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'La mayor riqueza del ser humano es el descontento que lo lleva a crecer.', 'Oliver Sacks', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Cada uno de nosotros es una criatura única y necesitamos escuchar a la persona.', 'Oliver Sacks', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'La evolución es un hecho, tanto como el sistema solar heliocéntrico o la edad de las rocas.', 'Richard Dawkins', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'La ciencia se alimenta del misterio. Como científico no sé qué descubriré a continuación.', 'Richard Dawkins', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Nada en biología tiene sentido excepto a la luz de la evolución.', 'Theodosius Dobzhansky', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Los más grandes científicos son también artistas.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La imaginación es más importante que el conocimiento. El conocimiento es limitado. La imaginación rodea el mundo.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['creativity', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Lo importante es no dejar de preguntarse. La curiosidad tiene su propia razón de existir.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Mira profundamente en la naturaleza y entonces comprenderás todo mejor.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La realidad es simplemente una ilusión, aunque muy persistente.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Si no puedes explicarlo de manera simple, no lo entiendes lo suficientemente bien.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'focus'], true, 'science'),
(gen_random_uuid(), 'La lógica te llevará de A a B. La imaginación te llevará a todas partes.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Lo más hermoso que podemos experimentar es lo misterioso. Es la fuente de todo arte y toda ciencia verdaderos.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'creativity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'El aprendizaje nunca agota la mente.', 'Leonardo da Vinci', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'curiosity', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'El placer más noble es el gozo de la comprensión.', 'Leonardo da Vinci', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'La simplicidad es la máxima sofisticación.', 'Leonardo da Vinci', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'creativity', 'focus'], true, 'science'),
(gen_random_uuid(), 'La naturaleza es la fuente de todo conocimiento verdadero.', 'Leonardo da Vinci', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Si quiero entender la función, estudio la estructura.', 'Francis Crick', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'curiosity', 'focus'], true, 'science'),
(gen_random_uuid(), 'Hemos descubierto el secreto de la vida.', 'Francis Crick', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'La genética es la clave para comprender toda la biología.', 'James Watson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'curiosity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Cada gran avance en la ciencia ha surgido de una nueva audacia de imaginación.', 'John Dewey', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['creativity', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Una nueva verdad científica no triunfa convenciendo a sus opositores, sino porque sus opositores finalmente mueren.', 'Max Planck', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'El descubrimiento científico solo lo logran quienes van tras él sin ningún propósito práctico en vista.', 'Max Planck', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'focus', 'learning'], true, 'science'),
(gen_random_uuid(), 'La ciencia colaborativa abarca generaciones y es más poderosa que el genio individual.', 'Carl Sagan', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'La ciencia no es perfecta. A menudo se usa mal. Simplemente es la mejor herramienta que tenemos.', 'Carl Sagan', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'La ausencia de evidencia no es evidencia de ausencia.', 'Carl Sagan', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Para pequeñas criaturas como nosotros, la inmensidad solo es soportable a través del amor.', 'Carl Sagan', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'La gran tragedia de la ciencia es el asesinato de una hermosa hipótesis por un hecho feo.', 'Thomas Huxley', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Las neuronas que se activan juntas se conectan juntas.', 'Donald Hebb', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'focus', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'La conciencia es el mayor misterio de toda la ciencia.', 'David Chalmers', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La mente es lo que hace el cerebro.', 'Steven Pinker', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'El lenguaje es una ventana a la naturaleza humana.', 'Steven Pinker', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'El progreso no es automático. Hay que creer en los datos, en la razón, en la ciencia.', 'Steven Pinker', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'discipline'], true, 'science'),
(gen_random_uuid(), 'El cerebro es el objeto más complejo del universo conocido.', 'Michio Kaku', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
