(gen_random_uuid(), 'El microorganismo más pequeño es más complejo que cualquier máquina que el hombre haya construido.', 'Louis Pasteur', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La ecología nos enseña que cada criatura está conectada con todas las demás.', 'Rachel Carson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Cada fósil es una ventana al pasado, un mensaje de la vida que fue.', 'Stephen Jay Gould', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'El gran milagro no es que el universo exista, sino que podamos comprenderlo.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'La ciencia nos dice que la realidad es siempre más extraña y más bella de lo que imaginamos.', 'Richard Feynman', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'No importa cuán hermosa sea tu teoría; si no concuerda con los experimentos, está equivocada.', 'Richard Feynman', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'discipline', 'learning'], true, 'science'),
(gen_random_uuid(), 'El cosmos es todo lo que hay, lo que hubo y lo que habrá.', 'Carl Sagan', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La razón es la única guía confiable en el laberinto de la naturaleza.', 'Voltaire', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'discipline'], true, 'science'),
(gen_random_uuid(), 'El experimento es el árbitro supremo de toda disputa científica.', 'Louis Pasteur', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['discipline', 'learning', 'focus'], true, 'science'),
(gen_random_uuid(), 'En la naturaleza no hay premios ni castigos; solo hay consecuencias.', 'Robert Ingersoll', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'discipline'], true, 'science'),
(gen_random_uuid(), 'La ciencia es la herramienta más poderosa que tiene la humanidad para resolver problemas.', 'Neil deGrasse Tyson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'discipline'], true, 'science'),
(gen_random_uuid(), 'La ciencia trata de conocer los hechos. La filosofía trata de encontrarles sentido.', 'Bertrand Russell', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'La ciencia avanza en la oscuridad y a veces tropieza con la luz.', 'Isaac Asimov', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'El triunfo de la ciencia está en la capacidad de repetir y verificar un resultado.', 'Galileo Galilei', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['discipline', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Cuando miramos a una célula, miramos la historia de tres mil millones de años de evolución.', 'Lynn Margulis', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Los microorganismos son los ingenieros silenciosos del planeta.', 'Louis Pasteur', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'La geología es el libro de memorias de la Tierra, y las rocas son sus páginas.', 'Charles Lyell', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'La paleontología nos recuerda que la vida es frágil y que la extinción siempre acecha.', 'Stephen Jay Gould', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Mediante la observación repetida y sistemática, la ciencia revela la estructura oculta del mundo.', 'Galileo Galilei', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['learning', 'focus', 'discipline'], true, 'science'),
(gen_random_uuid(), 'La historia de la medicina es la historia de la humanidad misma.', 'Sherwin Nuland', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'La genética es el idioma en que la evolución escribe sus instrucciones.', 'Francis Crick', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Las estrellas son los laboratorios donde se cocinan los elementos que forman nuestros cuerpos.', 'Carl Sagan', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Cada descubrimiento científico abre nuevas preguntas que nunca antes habíamos considerado.', 'Max Planck', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'La ciencia es el fruto más noble del espíritu humano.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Cada vez que el ser humano ha mirado hacia el cielo, ha encontrado inspiración y propósito.', 'Neil deGrasse Tyson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'El proceso científico toma el deseo humano de entender y lo convierte en resultados medibles.', 'Neil deGrasse Tyson', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'learning', 'discipline'], true, 'science'),
(gen_random_uuid(), 'La vida es el arte de sacar conclusiones suficientes de datos insuficientes.', 'Samuel Butler', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['wisdom', 'creativity', 'learning'], true, 'science'),
(gen_random_uuid(), 'El ser humano es la única especie que investiga las leyes que rigen su propia existencia.', 'Richard Dawkins', 'philosophy', 'es', 'down', 'free', false, 'science', 'general_science', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science')
INSERT INTO quotes (id, text, author, category, lang, swipe_dir, pack_name, is_premium, content_type, sub_category, tags, is_hidden_mode, locked_by) VALUES
(gen_random_uuid(), 'God does not play dice with the universe.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'If you can''t explain it simply, you don''t understand it well enough.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'focus'], true, 'science'),
(gen_random_uuid(), 'The most beautiful experience we can have is the mysterious. It is the fundamental emotion which stands at the cradle of true art and true science.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'creativity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Imagination is more important than knowledge. Knowledge is limited. Imagination encircles the world.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['creativity', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Time is an illusion, lunchtime doubly so.', 'Douglas Adams', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The most incomprehensible thing about the universe is that it is comprehensible.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'If I have seen further than others, it is by standing upon the shoulders of giants.', 'Isaac Newton', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'What we know is a drop, what we don''t know is an ocean.', 'Isaac Newton', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Nature is pleased with simplicity. And nature is no dummy.', 'Isaac Newton', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Gravity explains the motions of the planets, but it cannot explain who sets the planets in motion.', 'Isaac Newton', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'To every action there is always an equal and opposite reaction.', 'Isaac Newton', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'In physics, you don''t have to go around making trouble for yourself — nature does it for you.', 'Frank Wilczek', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Not only is the universe stranger than we think, it is stranger than we can think.', 'Werner Heisenberg', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'An expert is a person who has found out by his own painful experience all the mistakes that one can make in a very narrow field.', 'Niels Bohr', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'self_improvement', 'learning'], true, 'science'),
(gen_random_uuid(), 'If quantum mechanics hasn''t profoundly shocked you, you haven''t understood it yet.', 'Niels Bohr', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Everything we call real is made of things that cannot be regarded as real.', 'Niels Bohr', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Those who are not shocked when they first come across quantum theory cannot possibly have understood it.', 'Niels Bohr', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The electron is not as simple as it looks.', 'W.L. Bragg', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Science is not only compatible with spirituality; it is a profound source of spirituality.', 'Carl Sagan', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The laws of physics are the canvas God lays down on which to paint his masterpiece.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'My goal is simple. It is a complete understanding of the universe, why it is as it is and why it exists at all.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'focus', 'discipline'], true, 'science'),
(gen_random_uuid(), 'Even if there is only one possible unified theory, it is just a set of rules and equations.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The universe doesn''t allow perfection.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'We are just an advanced breed of monkeys on a minor planet of a very average star.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'One of the basic rules of the universe is that nothing is perfect. Perfection simply doesn''t exist.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'self_improvement', 'learning'], true, 'science'),
(gen_random_uuid(), 'The radiation left over from the Big Bang is the same as that in your microwave oven but very much less powerful.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Black holes are where God divided by zero.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'An object at rest stays at rest and an object in motion stays in motion with the same speed and direction unless acted upon by an unbalanced force.', 'Isaac Newton', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'discipline', 'focus'], true, 'science'),
(gen_random_uuid(), 'Physics is imagination in a straightjacket.', 'John Moffat', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['creativity', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The important thing in science is not so much to obtain new facts as to discover new ways of thinking about them.', 'William Lawrence Bragg', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['creativity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'It doesn''t matter how beautiful your theory is, it doesn''t matter how smart you are. If it doesn''t agree with experiment, it''s wrong.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'discipline', 'learning'], true, 'science'),
(gen_random_uuid(), 'Physics is really nothing more than a search for ultimate simplicity.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'focus'], true, 'science'),
(gen_random_uuid(), 'Nature uses as little as possible of anything.', 'Johannes Kepler', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'focus', 'learning'], true, 'science'),
(gen_random_uuid(), 'When the solution is simple, God is answering.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'focus'], true, 'science'),
(gen_random_uuid(), 'Entropy is not what it used to be.', 'Anonymous', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The second law of thermodynamics says that entropy always increases. The most we can hope for is to keep it from increasing too quickly.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'discipline', 'learning'], true, 'science'),
(gen_random_uuid(), 'In thermodynamics there are three laws; a zeroth, a first, a second, and a third.', 'C.P. Snow', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'curiosity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The energy of the mind is the essence of life.', 'Aristotle', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Einstein''s theory of relativity says that time is not absolute; it depends on the observer.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Space and time are not conditions in which we live, but modes in which we think.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The most exciting phrase to hear in science is not ''Eureka'' but ''That''s funny''.', 'Isaac Asimov', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'creativity'], true, 'science'),
(gen_random_uuid(), 'In every atom, there is a universe. In every electron, there is a galaxy.', 'Niels Bohr', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The atom is not the smallest thing in the world. The nucleus is. And inside it, quarks.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'I think I can safely say that nobody understands quantum mechanics.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The whole of science is nothing more than a refinement of everyday thinking.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'E=mc² is probably the most famous equation in all of physics.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Mass and energy are both but different manifestations of the same thing.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The distinction between the past, present and future is only a stubbornly persistent illusion.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'When you sit with a nice girl for two hours you think it''s only a minute. But when you sit on a hot stove for a minute you think it''s two hours. That''s relativity.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'creativity'], true, 'science'),
(gen_random_uuid(), 'My work always tried to unite the true with the beautiful; but when I had to choose one or the other, I usually chose the beautiful.', 'Hermann Weyl', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The mathematician plays a game in which he himself invents the rules; the physicist plays a game in which the rules are provided by nature.', 'Paul Dirac', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'God used beautiful mathematics in creating the world.', 'Paul Dirac', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['creativity', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'In science one tries to tell people, in such a way as to be understood by everyone, something that no one ever knew before.', 'Paul Dirac', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'creativity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Pick a flower on Earth and you move the farthest star.', 'Paul Dirac', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Quantum mechanics is the description of the behavior of matter and light in all its details.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'curiosity', 'focus'], true, 'science'),
(gen_random_uuid(), 'I was born not knowing and have had only a little time to change that here and there.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'To those who do not know mathematics it is difficult to get across a real feeling as to the beauty, the deepest beauty, of nature.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'If you think you understand quantum mechanics, you don''t understand quantum mechanics.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'There''s plenty of room at the bottom.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'creativity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Heisenberg, unlike Bohr, couldn''t figure it out. Einstein couldn''t either. Feynman could, but then he admitted he couldn''t explain it.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'An experiment is the only means of knowledge at our disposal. Everything else is poetry, imagination.', 'Max Planck', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['discipline', 'learning', 'focus'], true, 'science'),
(gen_random_uuid(), 'When you change the way you look at things, the things you look at change.', 'Max Planck', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'self_improvement', 'creativity'], true, 'science'),
(gen_random_uuid(), 'I regard consciousness as fundamental. I regard matter as derivative from consciousness.', 'Max Planck', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Science cannot solve the ultimate mystery of nature. And that is because, in the last analysis, we ourselves are a part of the mystery.', 'Max Planck', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Light is the only mirror that does not deceive.', 'Albert Michelson', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The great equations of physics are not just about numbers; they are about the universe.', 'Frank Wilczek', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'In the quantum world, particles can be in two places at the same time until they are observed.', 'Erwin Schrödinger', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The present situation in physics is as if we know chess, but we don''t know why the moves are what they are.', 'Erwin Schrödinger', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'If you are not completely confused by quantum mechanics, you do not understand it.', 'John Wheeler', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'We are all connected; to each other biologically, to the earth chemically, to the rest of the universe atomically.', 'Neil deGrasse Tyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The universe is under no obligation to make sense to you.', 'Neil deGrasse Tyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'In cosmic time, none of us have been here very long.', 'Neil deGrasse Tyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The universe is expanding in every direction, just like your waistband after Thanksgiving.', 'Neil deGrasse Tyson', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Equipped with his five senses, man explores the universe around him and calls the adventure science.', 'Edwin Hubble', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
