(gen_random_uuid(), 'At absolute zero, all atomic motion ceases.', 'William Thomson', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'curiosity', 'wisdom'], true, 'science'),
