(gen_random_uuid(), 'When we look at the sky at night, we are looking back in time.', 'Carl Sagan', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The light from distant stars takes millions of years to reach us. We are seeing the universe as it was, not as it is.', 'Carl Sagan', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The cosmic microwave background is the afterglow of the Big Bang.', 'George Smoot', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The curvature of spacetime is what we feel as gravity.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
