(gen_random_uuid(), 'We are made of stardust, and to stardust we shall return.', 'Carl Sagan', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'To understand the atom is to understand the universe at its most fundamental level.', 'Niels Bohr', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Wave-particle duality is one of the most beautiful and mysterious aspects of quantum mechanics.', 'Louis de Broglie', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'creativity'], true, 'science'),
