(gen_random_uuid(), 'Pauli''s exclusion principle states that no two electrons can occupy the same quantum state.', 'Wolfgang Pauli', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'curiosity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Physics will never be complete. There will always be more to discover.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The Uncertainty Principle says that the more precisely you know the position of a particle, the less precisely you can know its momentum.', 'Werner Heisenberg', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
