(gen_random_uuid(), 'Physics describes what nature does. Philosophy asks why it does it.', 'Paul Davies', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The fine-tuning of the universe''s constants is one of the great mysteries of physics.', 'Paul Davies', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Physics tells us that the universe is 96 percent stuff we cannot see.', 'Brian Cox', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The more we learn about the universe, the more mysterious it becomes.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'A physicist is just an atom''s way of thinking about atoms.', 'George Wald', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'creativity'], true, 'science'),
(gen_random_uuid(), 'Space is not empty. It is full of energy.', 'Richard Feynman', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The vacuum of space is not empty. It seethes with virtual particles.', 'Stephen Hawking', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The hardest thing to explain is the glaringly evident which everybody had decided not to see.', 'Ayn Rand', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Mass tells spacetime how to curve, and curved spacetime tells mass how to move.', 'John Wheeler', 'philosophy', 'en', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
