INSERT INTO quotes (id, text, author, category, lang, swipe_dir, pack_name, is_premium, content_type, sub_category, tags, is_hidden_mode, locked_by) VALUES
(gen_random_uuid(), 'Dios no juega a los dados con el universo.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Lo más incomprensible del universo es que sea comprensible.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'La energía no puede ser creada ni destruida, solo transformada de una forma a otra.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'La distinción entre pasado, presente y futuro es solo una ilusión obstinadamente persistente.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'El espacio y el tiempo no son condiciones en las que vivimos, sino modos en que pensamos.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La teoría de la relatividad dice que el tiempo no es absoluto; depende del observador.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La masa y la energía son dos manifestaciones diferentes de la misma cosa.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La gravedad no es responsable de que la gente se enamore.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'creativity'], true, 'science'),
(gen_random_uuid(), 'Una teoría es tanto más impresionante cuanto mayor es la simplicidad de sus premisas.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'creativity', 'focus'], true, 'science'),
(gen_random_uuid(), 'Del caos, busca la simplicidad. De la discordia, encuentra la armonía. En medio de la dificultad yace la oportunidad.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'creativity', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'No podemos resolver problemas pensando de la misma manera en que los creamos.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'creativity', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'La soledad y el silencio de una vida tranquila estimulan la mente creativa.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['creativity', 'focus', 'discipline'], true, 'science'),
(gen_random_uuid(), 'La luz se comporta simultáneamente como partícula y como onda.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La velocidad de la luz es el límite de velocidad absoluto del universo.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'La curvatura del espacio-tiempo es lo que sentimos como gravedad.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Las ondas gravitacionales son ondas en el espacio-tiempo causadas por masas en aceleración.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'La relatividad general nos dice que los objetos masivos distorsionan el espacio y el tiempo a su alrededor.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Una teoría unificada de la física sería el triunfo final de la razón humana.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'discipline'], true, 'science'),
(gen_random_uuid(), 'Si he visto más lejos que otros, es porque me he apoyado en hombros de gigantes.', 'Isaac Newton', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'La naturaleza se complace con la simplicidad.', 'Isaac Newton', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'A toda acción siempre se opone una reacción igual y contraria.', 'Isaac Newton', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'La gravedad explica los movimientos de los planetas, pero no puede explicar quién pone a los planetas en movimiento.', 'Isaac Newton', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La fuerza de la gravedad actúa entre todos los objetos que tienen masa.', 'Isaac Newton', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['learning', 'curiosity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Si la mecánica cuántica no te ha perturbado profundamente, es que no la has entendido todavía.', 'Niels Bohr', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Todo lo que llamamos real está hecho de cosas que no pueden considerarse reales.', 'Niels Bohr', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'El principio de complementariedad nos dice que los objetos cuánticos tienen propiedades mutuamente excluyentes.', 'Niels Bohr', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Para entender el átomo es necesario entender el universo en su nivel más fundamental.', 'Niels Bohr', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'El principio de incertidumbre dice que cuanto más precisamente conoces la posición de una partícula, menos precisamente puedes conocer su momento.', 'Werner Heisenberg', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'La realidad que podemos expresar con palabras nunca es la realidad misma.', 'Werner Heisenberg', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'No solo el universo es más extraño de lo que suponemos; es más extraño de lo que podemos suponer.', 'Werner Heisenberg', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La ciencia natural no describe ni explica simplemente la naturaleza; es parte de la interacción entre la naturaleza y nosotros.', 'Werner Heisenberg', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'El matemático juega a un juego en el que él mismo inventa las reglas; el físico juega a un juego en el que las reglas las proporciona la naturaleza.', 'Paul Dirac', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Dios utilizó las matemáticas hermosas al crear el mundo.', 'Paul Dirac', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['creativity', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Coge una flor en la Tierra y moverás la estrella más lejana.', 'Paul Dirac', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Las leyes de la física son elegantes más allá de la comprensión humana.', 'Paul Dirac', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['creativity', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'El cosmos es como una vasta máquina cuyos engranajes están hechos de matemáticas.', 'Paul Dirac', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Creo que puedo afirmar con seguridad que nadie entiende la mecánica cuántica.', 'Richard Feynman', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'No importa cuán hermosa sea tu teoría; si no está de acuerdo con el experimento, está equivocada.', 'Richard Feynman', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'discipline', 'learning'], true, 'science'),
(gen_random_uuid(), 'Nací sin saber y he tenido solo un poco de tiempo para cambiar eso aquí y allá.', 'Richard Feynman', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Las ecuaciones de Maxwell de Maxwell han tenido un mayor impacto en la historia humana que cualquier diez presidentes.', 'Richard Feynman', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Hay mucho espacio en la parte inferior.', 'Richard Feynman', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'creativity', 'learning'], true, 'science'),
