INSERT INTO quotes (id, text, author, category, lang, swipe_dir, pack_name, is_premium, content_type, sub_category, tags, is_hidden_mode, locked_by) VALUES
(gen_random_uuid(), 'Mathematics is the language in which God has written the universe.', 'Galileo Galilei', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Pure mathematics is, in its way, the poetry of logical ideas.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Mathematics is the queen of sciences and number theory is the queen of mathematics.', 'Carl Friedrich Gauss', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'God made the integers; all the rest is the work of man.', 'Leopold Kronecker', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'curiosity', 'creativity'], true, 'science'),
(gen_random_uuid(), 'In mathematics, the art of asking questions is more valuable than solving problems.', 'Georg Cantor', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'creativity'], true, 'science'),
(gen_random_uuid(), 'Mathematics is not about numbers, equations, computations, or algorithms: it is about understanding.', 'William Paul Thurston', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'The essence of mathematics lies in its freedom.', 'Georg Cantor', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'A mathematician is a device for turning coffee into theorems.', 'Paul Erdős', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'focus', 'discipline'], true, 'science'),
(gen_random_uuid(), 'Mathematics is the only infinite human activity.', 'Paul Erdős', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'creativity'], true, 'science'),
(gen_random_uuid(), 'My brain is open.', 'Paul Erdős', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'learning', 'creativity'], true, 'science'),
(gen_random_uuid(), 'It is impossible to be a mathematician without being a poet in soul.', 'Sofia Kovalevskaya', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Mathematics, rightly viewed, possesses not only truth, but supreme beauty.', 'Bertrand Russell', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'The mathematician does not study pure mathematics because it is useful; he studies it because he delights in it and he delights in it because it is beautiful.', 'Henri Poincaré', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'To understand mathematics is to know what makes a good question.', 'Henri Poincaré', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Mathematics is the science of what is clear by itself.', 'Carl Jacobi', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'clarity'], true, 'science'),
(gen_random_uuid(), 'In mathematics you don''t understand things. You just get used to them.', 'John von Neumann', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'Anyone who considers arithmetical methods of producing random digits is, of course, in a state of sin.', 'John von Neumann', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'creativity', 'learning'], true, 'science'),
(gen_random_uuid(), 'There are only two kinds of math books: those you cannot read beyond the first sentence, and those you cannot read beyond the first page.', 'C.N. Yang', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Number theory is the queen of mathematics.', 'Carl Friedrich Gauss', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Do not worry about your difficulties in mathematics. I can assure you mine are still greater.', 'Albert Einstein', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'self_improvement', 'learning'], true, 'science'),
(gen_random_uuid(), 'God made the natural numbers; all else is the work of man.', 'Leopold Kronecker', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'curiosity', 'creativity'], true, 'science'),
(gen_random_uuid(), 'An equation for me has no meaning unless it expresses a thought of God.', 'Srinivasa Ramanujan', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'I have discovered a truly marvelous proof of this theorem, which this margin is too narrow to contain.', 'Pierre de Fermat', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'creativity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Give me a place to stand, and a lever long enough, and I will move the world.', 'Archimedes', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'discipline', 'creativity'], true, 'science'),
(gen_random_uuid(), 'Eureka!', 'Archimedes', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'creativity', 'learning'], true, 'science'),
(gen_random_uuid(), 'There is no royal road to geometry.', 'Euclid', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'discipline', 'learning'], true, 'science'),
(gen_random_uuid(), 'The laws of nature are written in the language of mathematics.', 'Galileo Galilei', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Mathematics is the alphabet with which God has written the universe.', 'Galileo Galilei', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'creativity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Logic is the beginning of wisdom, not the end.', 'Leonard Nimoy', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Algebra is the intellectual instrument which has been created for rendering clear the quantitative aspects of the world.', 'Alfred North Whitehead', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'A good proof is one that makes us wiser.', 'Yuri Manin', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'The infinite is nowhere an actual fact, but only a manner of speaking.', 'Carl Friedrich Gauss', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Geometry is the science of correct reasoning on incorrect figures.', 'George Polya', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'creativity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The study of mathematics, like the Nile, begins in minuteness but ends in magnificence.', 'Charles Caleb Colton', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'In mathematics the art of proposing a question must be held of higher value than solving it.', 'Georg Cantor', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'creativity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Equipped with his five senses, man explores the universe around him, calling the adventure mathematics.', 'Edwin Hubble', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Mathematics is the foundation upon which the edifice of science is built.', 'Henri Poincaré', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'The mathematical sciences particularly exhibit order, symmetry, and limitation; and these are the greatest forms of the beautiful.', 'Aristotle', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
