(gen_random_uuid(), 'The heart has its reasons which reason knows nothing of.', 'Blaise Pascal', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'All of humanity''s problems stem from man''s inability to sit quietly in a room alone.', 'Blaise Pascal', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'discipline', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'Imagination is the beginning of creation. You imagine what you desire, you will what you imagine, and at last you create what you will.', 'George Bernard Shaw', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'discipline', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'The joy of suddenly learning a former secret and the joy of suddenly discovering a hitherto unknown truth are the same to me — both have the flash of enlightenment.', 'Paul Erdős', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'creativity'], true, 'science'),
(gen_random_uuid(), 'Mathematics consists of proving the most obvious thing in the least obvious way.', 'George Polya', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'discipline'], true, 'science'),
(gen_random_uuid(), 'When I am asked what mathematics is, I cannot give a satisfactory answer except to say it is the study of beautiful things.', 'Marcus du Sautoy', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'curiosity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The abstract formulation is almost always more powerful and more revealing than the concrete one.', 'Michael Atiyah', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Mathematics is the study of things that come out the same no matter how you look at them.', 'Michael Atiyah', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Algebra is the language of mathematics; geometry is its vision.', 'Michael Atiyah', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'There is no problem in all mathematics that cannot be solved by direct counting.', 'Ernst Mach', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'discipline', 'focus'], true, 'science'),
(gen_random_uuid(), 'The deepest truths in mathematics are also the simplest.', 'Leonhard Euler', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'creativity', 'learning'], true, 'science'),
(gen_random_uuid(), 'To write a poem about mathematics is to become a mathematician.', 'Leonhard Euler', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The sum of all divisors of a perfect number equals twice the number.', 'Leonhard Euler', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['learning', 'curiosity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Mathematics is not a deductive science — that''s a cliché. When you try to prove a theorem, you don''t just list the hypotheses, and then start to reason.', 'Paul Halmos', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The best mathematics is not known to those outside of mathematics.', 'Timothy Gowers', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Every child is a mathematician. Mathematics is pattern recognition.', 'Keith Devlin', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'learning', 'creativity'], true, 'science'),
(gen_random_uuid(), 'Numbers are the free creation of human intellect.', 'Richard Dedekind', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'A differential equation is a mathematical relationship between a function and its derivatives.', 'Carl Friedrich Gauss', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['learning', 'curiosity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Mathematics is the science of drawing necessary conclusions.', 'Benjamin Peirce', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'discipline'], true, 'science'),
(gen_random_uuid(), 'We must be able to read in the book of nature. This book is written in the language of mathematics.', 'Galileo Galilei', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The essence of the mathematical method is the method of definitions.', 'Bertrand Russell', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'discipline'], true, 'science'),
(gen_random_uuid(), 'All my life I have been troubled by the same feeling that the most important things about mathematics are impossible to teach.', 'Paul Halmos', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'The sequence of prime numbers is one of the great mysteries of mathematics.', 'Marcus du Sautoy', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The twin prime conjecture is one of the oldest unsolved problems in mathematics.', 'Bernhard Riemann', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'discipline'], true, 'science'),
(gen_random_uuid(), 'A circle is the simplest of all closed curves, yet it contains the mystery of pi.', 'Leonhard Euler', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'creativity'], true, 'science'),
(gen_random_uuid(), 'The concept of a function is the cornerstone of modern mathematics.', 'Peter Gustav Lejeune Dirichlet', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['learning', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Mathematical thinking is the key to solving problems in all fields of human endeavor.', 'John von Neumann', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'creativity', 'discipline'], true, 'science'),
(gen_random_uuid(), 'Wherever there is a problem to be solved, mathematics provides the framework.', 'John Nash', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'creativity', 'discipline'], true, 'science'),
(gen_random_uuid(), 'The beauty of mathematics is that you can always find something new.', 'Maryam Mirzakhani', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'creativity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Abstraction is what makes mathematics universal.', 'Michael Atiyah', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The integers are the foundation; everything else is built upon them.', 'Carl Friedrich Gauss', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'discipline'], true, 'science'),
(gen_random_uuid(), 'Good mathematics is characterized by economy of means and elegance of expression.', 'G.H. Hardy', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'focus'], true, 'science'),
(gen_random_uuid(), 'Mathematics is not the study of an imaginary world, but of a real and important aspect of the world.', 'Keith Devlin', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'The computer is the telescope of the mind.', 'Alan Turing', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Mathematical truth is not a human convention; it exists independently of us.', 'Plato', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Mathematics is about meaning, not mechanics.', 'Keith Devlin', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'There is no branch of the tree of knowledge that has contributed more to the growth of the others than mathematics.', 'Augustus De Morgan', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'The philosophy of mathematics is concerned with the nature and foundations of mathematical knowledge.', 'Bertrand Russell', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The Fibonacci sequence appears throughout nature: in sunflowers, pine cones, and spiral galaxies.', 'Leonardo Fibonacci', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'creativity'], true, 'science'),
(gen_random_uuid(), 'The golden ratio is the most irrational of all irrational numbers.', 'Leonhard Euler', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'creativity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'A knot is a closed loop in three-dimensional space. Knot theory is the mathematical study of knots.', 'Peter Tait', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'In the end, mathematics is about truth. And truth is beautiful.', 'Timothy Gowers', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'creativity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Euclid alone has looked on Beauty bare.', 'Edna St. Vincent Millay', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'One of the endlessly amusing things about mathematics is that it surprises you.', 'Marcus du Sautoy', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'creativity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'The great mathematicians of history were guided by intuition and beauty, not just by logical rigor.', 'Henri Poincaré', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Zero is the most profound discovery in mathematics. It changed everything.', 'Brahmagupta', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'creativity'], true, 'science'),
(gen_random_uuid(), 'The discovery of zero was the turning point in the history of human thought.', 'Carl Friedrich Gauss', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Mathematics has the capacity to describe everything in the universe with perfect precision.', 'Max Tegmark', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'If the universe is described by mathematics, then mathematics is the language of God.', 'Max Tegmark', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'creativity', 'curiosity'], true, 'science')
INSERT INTO quotes (id, text, author, category, lang, swipe_dir, pack_name, is_premium, content_type, sub_category, tags, is_hidden_mode, locked_by) VALUES
(gen_random_uuid(), 'Las matemáticas son el lenguaje en que Dios ha escrito el universo.', 'Galileo Galilei', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Las matemáticas puras son, en cierto modo, la poesía de las ideas lógicas.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Las matemáticas son la reina de las ciencias y la teoría de números es la reina de las matemáticas.', 'Carl Friedrich Gauss', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'La esencia de las matemáticas reside en su libertad.', 'Georg Cantor', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'En matemáticas, el arte de hacer preguntas es más valioso que resolver problemas.', 'Georg Cantor', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'creativity'], true, 'science'),
(gen_random_uuid(), 'Las matemáticas no se tratan de números, ecuaciones, cálculos o algoritmos: se trata de comprensión.', 'William Paul Thurston', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Un matemático es un dispositivo para convertir café en teoremas.', 'Paul Erdős', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'focus', 'discipline'], true, 'science'),
(gen_random_uuid(), 'Las matemáticas son la única actividad humana infinita.', 'Paul Erdős', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'creativity'], true, 'science'),
(gen_random_uuid(), 'Es imposible ser matemático sin ser poeta en el alma.', 'Sofia Kovalevskaya', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Las matemáticas, vistas correctamente, poseen no solo verdad, sino belleza suprema.', 'Bertrand Russell', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'El matemático no estudia matemáticas puras porque son útiles; las estudia porque las disfruta y las disfruta porque son hermosas.', 'Henri Poincaré', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'En matemáticas, no entiendes las cosas. Solo te acostumbras a ellas.', 'John von Neumann', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'No te preocupes por tus dificultades en matemáticas. Puedo asegurarte que las mías son aún mayores.', 'Albert Einstein', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'self_improvement', 'learning'], true, 'science'),
(gen_random_uuid(), 'Una ecuación para mí no tiene significado a menos que exprese un pensamiento de Dios.', 'Srinivasa Ramanujan', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'He descubierto una prueba verdaderamente maravillosa de este teorema, que este margen es demasiado estrecho para contener.', 'Pierre de Fermat', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'creativity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Dame un punto de apoyo y una palanca suficientemente larga, y moveré el mundo.', 'Arquímedes', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'discipline', 'creativity'], true, 'science'),
(gen_random_uuid(), '¡Eureka!', 'Arquímedes', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'creativity', 'learning'], true, 'science'),
(gen_random_uuid(), 'No hay camino real hacia la geometría.', 'Euclides', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'discipline', 'learning'], true, 'science'),
(gen_random_uuid(), 'Las leyes de la naturaleza están escritas en el lenguaje de las matemáticas.', 'Galileo Galilei', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Las matemáticas son el alfabeto con el que Dios ha escrito el universo.', 'Galileo Galilei', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'creativity', 'learning'], true, 'science'),
(gen_random_uuid(), 'La lógica es el comienzo de la sabiduría, no el final.', 'Leonard Nimoy', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Una buena prueba es aquella que nos hace más sabios.', 'Yuri Manin', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'La geometría es la ciencia del razonamiento correcto sobre figuras incorrectas.', 'George Polya', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'creativity', 'learning'], true, 'science'),
(gen_random_uuid(), 'El arte de hacer preguntas en matemáticas debe tenerse en mayor valor que resolverlas.', 'Georg Cantor', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'creativity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Las matemáticas son la ciencia de los patrones y la estructura.', 'Keith Devlin', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Los descubrimientos matemáticos más grandes a menudo vienen cuando los matemáticos no los están buscando.', 'Srinivasa Ramanujan', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'creativity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Los patrones del matemático, como los del pintor o el poeta, deben ser hermosos.', 'G.H. Hardy', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La belleza es la primera prueba: no hay lugar permanente en el mundo para las matemáticas feas.', 'G.H. Hardy', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Un matemático, como un pintor o un poeta, es un creador de patrones.', 'G.H. Hardy', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'No hay rama de las matemáticas, por abstracta que sea, que no pueda aplicarse algún día a los fenómenos del mundo real.', 'Nikolai Lobachevsky', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La identidad de Euler es la ecuación más bella de las matemáticas.', 'Leonhard Euler', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La belleza de las matemáticas solo se muestra a sus seguidores más pacientes.', 'Maryam Mirzakhani', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'discipline', 'creativity'], true, 'science'),
(gen_random_uuid(), 'La única manera de aprender matemáticas es hacer matemáticas.', 'Paul Halmos', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['discipline', 'learning', 'focus'], true, 'science'),
(gen_random_uuid(), 'El infinito no es un número; es un concepto que captura la idea de progresión sin fin.', 'Georg Cantor', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'En realidad hay más números reales entre 0 y 1 que enteros en total.', 'Georg Cantor', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Lo veo, pero no lo creo.', 'Georg Cantor', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Las matemáticas son el arte de dar el mismo nombre a cosas diferentes.', 'Henri Poincaré', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'El arte de hacer matemáticas consiste en encontrar ese caso especial que contiene todos los gérmenes de la generalidad.', 'David Hilbert', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'focus'], true, 'science'),
(gen_random_uuid(), 'Debemos saber, lo sabremos.', 'David Hilbert', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['discipline', 'focus', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Las matemáticas no conocen razas ni fronteras geográficas.', 'David Hilbert', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Todo problema tiene una solución. Solo tienes que ser suficientemente creativo para encontrarla.', 'David Hilbert', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'discipline', 'focus'], true, 'science'),
(gen_random_uuid(), 'El avance de las matemáticas depende de la riqueza y la dificultad de sus problemas.', 'David Hilbert', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'discipline', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Una verdad matemática no es algo que descubrimos; es algo que inventamos.', 'Henri Poincaré', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Las matemáticas toman al ser humano hacia la región de la necesidad absoluta.', 'Bertrand Russell', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'El cálculo es el lenguaje del cambio. Sin él, no podemos entender la física.', 'Isaac Newton', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['learning', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'El teorema fundamental del cálculo vincula la integración y la diferenciación.', 'Gottfried Wilhelm Leibniz', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['learning', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Pi no es solo un número; es una ventana a la naturaleza del círculo y el universo.', 'Leonhard Euler', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La estadística es la gramática de la ciencia.', 'Karl Pearson', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'La teoría de probabilidades es en el fondo nada más que sentido común reducido al cálculo.', 'Pierre-Simon Laplace', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
