(gen_random_uuid(), 'La óptica cuántica estudia cómo la luz y la materia interactúan a nivel fundamental.', 'Roy Glauber', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'El efecto túnel cuántico permite que las partículas atraviesen barreras que clásicamente serían infranqueables.', 'George Gamow', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'creativity'], true, 'science'),
(gen_random_uuid(), 'La condensación de Bose-Einstein es el estado de la materia más cercano al cero absoluto.', 'Satyendra Nath Bose', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Los agujeros negros son regiones del espacio-tiempo donde la gravedad es tan extrema que nada escapa.', 'Stephen Hawking', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La radiación de Hawking sugiere que los agujeros negros no son completamente negros.', 'Stephen Hawking', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'creativity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'La materia oscura es invisible pero su presencia se siente en la dinámica de las galaxias.', 'Fritz Zwicky', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La expansión acelerada del universo implica la existencia de una energía oscura misteriosa.', 'Saul Perlmutter', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Las ondas gravitacionales son el sonido del universo, vibraciones del espacio-tiempo mismo.', 'Kip Thorne', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'creativity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'La inflación cósmica explica por qué el universo es tan homogéneo e isotrópico a gran escala.', 'Alan Guth', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'El modelo estándar de la física de partículas es la descripción más precisa de la naturaleza jamás lograda.', 'Steven Weinberg', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'La física del plasma estudia el cuarto estado de la materia que forma las estrellas.', 'Hannes Alfvén', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La física de la materia condensada es el campo de la física con más aplicaciones tecnológicas.', 'Philip W. Anderson', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'learning', 'creativity'], true, 'science'),
(gen_random_uuid(), 'La dualidad onda-corpúsculo es uno de los aspectos más perturbadores de la mecánica cuántica.', 'Louis de Broglie', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'El láser es una de las aplicaciones más directas de la mecánica cuántica en la tecnología.', 'Theodore Maiman', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['creativity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'La polarización de la luz revela propiedades fundamentales de las ondas electromagnéticas.', 'Augustin-Jean Fresnel', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'La fricción, aunque a menudo indeseada, es una fuerza indispensable para la vida cotidiana.', 'Leonardo da Vinci', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'La resonancia es el fenómeno que destruyó el puente de Tacoma y el que afina una guitarra.', 'John William Strutt', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La física siempre será incompleta mientras no podamos unificar la gravedad con las otras fuerzas.', 'Michio Kaku', 'philosophy', 'es', 'down', 'free', false, 'science', 'physics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science')
INSERT INTO quotes (id, text, author, category, lang, swipe_dir, pack_name, is_premium, content_type, sub_category, tags, is_hidden_mode, locked_by) VALUES
(gen_random_uuid(), 'Mathematics is not about numbers, equations, or algorithms; it is about understanding.', 'William Paul Thurston', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'A proof is a proof. What kind of a proof? A proof that proves.', 'Jean Chrétien', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'discipline', 'focus'], true, 'science'),
(gen_random_uuid(), 'Mathematics is the art of giving the same name to different things.', 'Henri Poincaré', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The shortest path between two truths in the real domain passes through the complex domain.', 'Jacques Hadamard', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'curiosity', 'creativity'], true, 'science'),
(gen_random_uuid(), 'Prime numbers are the atoms of arithmetic; the building blocks from which all other numbers are made.', 'Marcus du Sautoy', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The Riemann hypothesis is the most important unsolved problem in mathematics.', 'David Hilbert', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'discipline'], true, 'science'),
(gen_random_uuid(), 'Topology is the mathematics of rubber-sheet geometry, where stretching is allowed but not tearing.', 'Leonard Euler', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'creativity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Calculus is the mathematics of change and it underlies all of modern science.', 'Isaac Newton', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Linear algebra is the grammar that allows us to describe data, transformations, and reality.', 'Gilbert Strang', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['learning', 'discipline', 'focus'], true, 'science'),
(gen_random_uuid(), 'Probability theory is nothing but common sense reduced to calculation.', 'Pierre-Simon Laplace', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'discipline'], true, 'science'),
(gen_random_uuid(), 'The art of doing mathematics consists in finding that special case which contains all the germs of generality.', 'David Hilbert', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Symmetry is a vast subject, significant in art and nature. Mathematics lies at its root.', 'Hermann Weyl', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'A mathematician is a machine for turning coffee into theorems.', 'Paul Erdős', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'discipline', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Collaboration is the most powerful tool in modern mathematics.', 'Paul Erdős', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['discipline', 'creativity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'In mathematics you don''t understand things; you just get used to them.', 'John von Neumann', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'discipline', 'learning'], true, 'science'),
(gen_random_uuid(), 'The infinite is not a difficult concept; it is the most natural concept in mathematics.', 'Georg Cantor', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'creativity'], true, 'science'),
(gen_random_uuid(), 'Game theory reveals the hidden logic behind competition, cooperation, and conflict.', 'John Nash', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'Number theory is full of problems that are easy to state and devilishly hard to prove.', 'Pierre de Fermat', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'discipline', 'learning'], true, 'science'),
(gen_random_uuid(), 'Geometry is the art of correct reasoning about incorrect figures.', 'Henri Poincaré', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'creativity', 'discipline'], true, 'science'),
(gen_random_uuid(), 'The connection between mathematics and music is one of the deepest in all of human thought.', 'G.H. Hardy', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Mathematical truth is eternal and independent of human thought.', 'G.H. Hardy', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Statistics is the grammar of science.', 'Karl Pearson', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'discipline'], true, 'science'),
(gen_random_uuid(), 'Every mathematician secretly believes that their work is the most important.', 'Gian-Carlo Rota', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'discipline'], true, 'science'),
(gen_random_uuid(), 'Mathematical abstraction is the engine of scientific progress.', 'Michael Atiyah', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'A mathematician, like a painter or a poet, is a maker of patterns.', 'G.H. Hardy', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The unreasonable effectiveness of mathematics in the natural sciences is a gift we should not take for granted.', 'Eugene Wigner', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'curiosity', 'creativity'], true, 'science'),
(gen_random_uuid(), 'Gödel''s incompleteness theorems showed that no formal system can be both complete and consistent.', 'Kurt Gödel', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'The beauty of mathematics is that it transcends language, culture, and even time itself.', 'Roger Penrose', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'creativity', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Complex numbers are the completion of the real numbers into a more perfect algebraic structure.', 'Carl Friedrich Gauss', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'The four color theorem proved that any map can be colored with at most four colors without ambiguity.', 'Kenneth Appel', 'philosophy', 'en', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'creativity'], true, 'science')
INSERT INTO quotes (id, text, author, category, lang, swipe_dir, pack_name, is_premium, content_type, sub_category, tags, is_hidden_mode, locked_by) VALUES
(gen_random_uuid(), 'Las matemáticas son el lenguaje universal que hablan todas las civilizaciones.', 'Carl Friedrich Gauss', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'creativity', 'learning'], true, 'science'),
(gen_random_uuid(), 'La teoría de probabilidad es el sentido común reducido a cálculo.', 'Pierre-Simon Laplace', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'discipline'], true, 'science'),
(gen_random_uuid(), 'La topología estudia las propiedades que se conservan bajo deformaciones continuas.', 'Henri Poincaré', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'El cálculo diferencial describe cómo cambian las cosas; el cálculo integral acumula esos cambios.', 'Gottfried Wilhelm Leibniz', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Los números primos son los átomos de los números enteros, los ladrillos del universo numérico.', 'Marcus du Sautoy', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La hipótesis de Riemann sigue siendo el problema más importante de las matemáticas sin resolver.', 'David Hilbert', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'discipline'], true, 'science'),
(gen_random_uuid(), 'El álgebra lineal es la gramática que nos permite describir datos y transformaciones del mundo real.', 'Gilbert Strang', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['learning', 'discipline', 'focus'], true, 'science'),
(gen_random_uuid(), 'Un matemático es una máquina para convertir café en teoremas.', 'Paul Erdős', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'discipline', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'En matemáticas no entiendes las cosas; simplemente te acostumbras a ellas.', 'John von Neumann', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'discipline', 'learning'], true, 'science'),
(gen_random_uuid(), 'La teoría de juegos revela la lógica oculta detrás de la competencia, la cooperación y el conflicto.', 'John Nash', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'La geometría es el arte de razonar correctamente sobre figuras incorrectas.', 'Henri Poincaré', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'creativity', 'discipline'], true, 'science'),
(gen_random_uuid(), 'Las estadísticas son la gramática de la ciencia moderna.', 'Karl Pearson', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'discipline'], true, 'science'),
(gen_random_uuid(), 'La simetría es un concepto vasto, significativo en el arte y la naturaleza, y las matemáticas están en su raíz.', 'Hermann Weyl', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La verdad matemática es eterna e independiente del pensamiento humano.', 'G.H. Hardy', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'learning', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Un matemático, como un pintor o un poeta, es un creador de patrones.', 'G.H. Hardy', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La eficacia irrazonable de las matemáticas en las ciencias naturales es un regalo que no debemos dar por sentado.', 'Eugene Wigner', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'curiosity', 'creativity'], true, 'science'),
(gen_random_uuid(), 'Los teoremas de incompletitud de Gödel mostraron que ningún sistema formal puede ser a la vez completo y consistente.', 'Kurt Gödel', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'La belleza de las matemáticas radica en que trasciende el lenguaje, la cultura y el tiempo.', 'Roger Penrose', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'creativity', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'Los números complejos completaron los números reales hacia una estructura algebraica más perfecta.', 'Carl Friedrich Gauss', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'La abstracción matemática es el motor del progreso científico en todas las disciplinas.', 'Michael Atiyah', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'El número pi aparece en lugares inesperados, desde los círculos hasta la distribución normal.', 'Leonhard Euler', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'creativity'], true, 'science'),
(gen_random_uuid(), 'La identidad de Euler conecta los cinco números más importantes de las matemáticas en una sola ecuación.', 'Leonhard Euler', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['creativity', 'wisdom', 'curiosity'], true, 'science'),
(gen_random_uuid(), 'La teoría del caos muestra que pequeñas diferencias en condiciones iniciales producen grandes divergencias.', 'Edward Lorenz', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Los fractales revelan que la complejidad puede emerger de reglas matemáticas sorprendentemente simples.', 'Benoit Mandelbrot', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'creativity', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'La combinatoria cuenta las posibilidades del universo y revela la estructura de la complejidad.', 'Paul Erdős', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'learning', 'wisdom'], true, 'science'),
(gen_random_uuid(), 'Las matemáticas son la ciencia del orden; el caos matemático es el orden que todavía no entendemos.', 'James Gleick', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'curiosity', 'learning'], true, 'science'),
(gen_random_uuid(), 'La teoría de grafos modela las redes, desde las redes sociales hasta el cerebro humano.', 'Leonhard Euler', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'creativity', 'learning'], true, 'science'),
(gen_random_uuid(), 'El teorema de los cuatro colores fue el primer teorema demostrado con la ayuda de un ordenador.', 'Kenneth Appel', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'creativity'], true, 'science'),
(gen_random_uuid(), 'El último teorema de Fermat esperó 358 años para ser demostrado; la perseverancia vence al tiempo.', 'Andrew Wiles', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['discipline', 'wisdom', 'self_improvement'], true, 'science'),
(gen_random_uuid(), 'La teoría de números es una fuente inagotable de problemas bellos y profundos.', 'Carl Friedrich Gauss', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['curiosity', 'wisdom', 'learning'], true, 'science'),
(gen_random_uuid(), 'Las matemáticas no conocen razas ni fronteras geográficas; para las matemáticas, el mundo cultural es un país.', 'David Hilbert', 'philosophy', 'es', 'down', 'free', false, 'science', 'mathematics', ARRAY['wisdom', 'creativity', 'learning'], true, 'science')
